const data = $input.first().json.body || $input.first().json;
const maintenant = new Date();

// J+1 = 24h après
const emailJ1 = new Date(maintenant.getTime() + 24 * 60 * 60 * 1000);
// J+3 = 72h après
const emailJ3 = new Date(maintenant.getTime() + 72 * 60 * 60 * 1000);

// Formater les articles du panier
const articlesHTML = (data.panier?.items || []).map(item => 
  `<li>${item.nom} × ${item.quantite} — ${item.prix}€</li>`
).join('');

const totalFormate = parseFloat(data.panier?.total || 0).toFixed(2);

return [{
  json: {
    panier: { ...data.panier, articlesHTML, totalFormate },
    client: data.client,
    config: {
      nomBoutique: data.config?.nomBoutique || 'La Boutique',
      urlBoutique: data.config?.urlBoutique || '#',
      codePromo: data.config?.codePromo || 'REVIENS10',
      remisePromo: data.config?.remisePromo || '10%',
      emailExpedition: data.config?.emailExpedition || 'noreply@marrynov.re'
    },
    timestamps: {
      emailJ1: emailJ1.toISOString(),
      emailJ3: emailJ3.toISOString()
    },
    panierRepriseUrl: `${data.config?.urlBoutique}/panier/reprendre/${data.panier?.id}`
  }
}];
